public record EditorMemento(string Text);

public class Editor {
  public string Text { get; private set; } = string.Empty;
  public void Type(string text) => Text += text;
  public EditorMemento Save() => new(Text);
  public void Restore(EditorMemento memento) => Text = memento.Text;
}

public class History {
  private readonly Stack<EditorMemento> _stack = new();
  public void Push(EditorMemento m) => _stack.Push(m);
  public EditorMemento Pop() => _stack.Pop();
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void Editor_RestoresPreviousStateFromMemento() {
  var editor = new Editor();
  var history = new History();
  editor.Type("Hello");
  history.Push(editor.Save());
  editor.Type(" World");
  editor.Restore(history.Pop());
  Assert.AreEqual("Hello", editor.Text);
}

[TestMethod]
public void Memento_DoesNotExposeOriginatorInternals() {
  var m = new EditorMemento("snapshot");
  Assert.AreEqual("snapshot", m.Text);
}
